#include "controllers/creative_controller.h"
#include "services/creative_service.h"
namespace aegis {
CreativeController::CreativeController(CreativeService*s,QObject*p):QObject(p),service_(s){connect(s,&CreativeService::chunk,this,[this](const QString&id,const QString&d){if(id!=requestId_)return;output_+=d;outputBytes_=static_cast<quint64>(output_.toUtf8().size());emit outputChanged();emit resultChanged();emit chunk(id,d);});connect(s,&CreativeService::finished,this,[this](const QString&id,const dto::CreativeResult&r){if(id!=requestId_)return;busy_=false;output_=r.text;finishReason_=r.finishReason;outputBytes_=r.outputBytes;emit busyChanged();emit outputChanged();emit resultChanged();emit finished(id,r.text,r.finishReason);});connect(s,&CreativeService::failed,this,[this](const QString&id,const AegisError&e){if(id!=requestId_)return;busy_=false;finishReason_=QStringLiteral("error");emit busyChanged();emit resultChanged();emit failed(id,e.userMessage);});}
bool CreativeController::busy()const{return busy_;} QString CreativeController::output()const{return output_;} QString CreativeController::finishReason()const{return finishReason_;} quint64 CreativeController::outputBytes()const{return outputBytes_;}
QString CreativeController::generate(int b,QString m,QString p,double t,int n){if(busy_)cancel();output_.clear();finishReason_.clear();outputBytes_=0;busy_=true;emit outputChanged();emit resultChanged();emit busyChanged();requestId_=service_->generate({static_cast<dto::CreativeBackend>(b),std::move(m),std::move(p),t,n});return requestId_;}
void CreativeController::cancel(){if(!requestId_.isEmpty())service_->cancel(requestId_);}
}
